from langgraph.graph import StateGraph, END from typing import TypedDict, Literal
class TeamState(TypedDict): input: str next_agent: str messages: list final_answer: str
def supervisor(state: TeamState) -> TeamState: """Route to appropriate specialist.""" prompt = f"""You are a supervisor. Route this query to the right agent. Options: researcher, coder, writer
Query: {state['input']}
Respond with just the agent name."""
response = model.invoke(prompt) return {"next_agent": response.content.strip().lower()}
def researcher(state: TeamState) -> TeamState: """Research specialist.""" response = model.invoke(f"Research this: {state['input']}") return {"messages": [f"Researcher: {response.content}"]}
def coder(state: TeamState) -> TeamState: """Coding specialist.""" response = model.invoke(f"Write code for: {state['input']}") return {"messages": [f"Coder: {response.content}"]}
def writer(state: TeamState) -> TeamState: """Writing specialist.""" response = model.invoke(f"Write content for: {state['input']}") return {"messages": [f"Writer: {response.content}"]}
def route_to_agent(state: TeamState) -> str: return state["next_agent"]
# Build graph = StateGraph(TeamState) graph.add_node("supervisor", supervisor) graph.add_node("researcher", researcher) graph.add_node("coder", coder) graph.add_node("writer", writer)
graph.set_entry_point("supervisor") graph.add_conditional_edges( "supervisor", route_to_agent, {"researcher": "researcher", "coder": "coder", "writer": "writer"} ) graph.add_edge("researcher", END) graph.add_edge("coder", END) graph.add_edge("writer", END)
team = graph.compile()

class DebateState(TypedDict):
    topic: str
    positions: list[dict]
    round: int
    consensus: str | None

def agent_a(state: DebateState) -> DebateState:
    """First debater."""
    context = "\n".join([f"{p['agent']}: {p['argument']}" for p in state["positions"]])

    prompt = f"""You are Agent A in a debate.
    Topic: {state['topic']}
    Previous arguments: {context}

    Present your position."""

    response = model.invoke(prompt)
    return {
        "positions": [{"agent": "A", "argument": response.content}],
        "round": state["round"] + 1
    }

def agent_b(state: DebateState) -> DebateState:
    """Second debater."""
    context = "\n".join([f"{p['agent']}: {p['argument']}" for p in state["positions"]])

    prompt = f"""You are Agent B in a debate.
    Topic: {state['topic']}
    Previous arguments: {context}

    Present your counterargument."""

    response = model.invoke(prompt)
    return {"positions": [{"agent": "B", "argument": response.content}]}

def judge(state: DebateState) -> DebateState:
    """Judge the debate."""
    context = "\n".join([f"{p['agent']}: {p['argument']}" for p in state["positions"]])

    prompt = f"""You are a judge.
    Topic: {state['topic']}
    Arguments: {context}

    Determine if consensus is reached. If yes, summarize it.
    If no, say "No consensus"."""

    response = model.invoke(prompt)
    consensus = None if "No consensus" in response.content else response.content
    return {"consensus": consensus}

def should_continue_debate(state: DebateState) -> str:
    if state.get("consensus"):
        return END
    if state["round"] >= 5:
        return END
    return "agent_a"

# Build
graph = StateGraph(DebateState)
graph.add_node("agent_a", agent_a)
graph.add_node("agent_b", agent_b)
graph.add_node("judge", judge)

graph.set_entry_point("agent_a")
graph.add_edge("agent_a", "agent_b")
graph.add_edge("agent_b", "judge")
graph.add_conditional_edges("judge", should_continue_debate)

debate = graph.compile()

class HierarchicalState(TypedDict): task: str team: str subtasks: list[str] results: list[str] final_output: str
# Research team def research_lead(state: HierarchicalState) -> HierarchicalState: """Research team lead - delegates to researchers.""" return {"subtasks": ["search web", "analyze papers", "summarize"]}
research_team = StateGraph(HierarchicalState) research_team.add_node("lead", research_lead) research_team.add_node("searcher", searcher_node) research_team.add_node("analyzer", analyzer_node) # ... build team
# Engineering team def eng_lead(state: HierarchicalState) -> HierarchicalState: """Engineering team lead.""" return {"subtasks": ["design", "implement", "test"]}
eng_team = StateGraph(HierarchicalState) eng_team.add_node("lead", eng_lead) # ... build team
# Top-level coordinator def coordinator(state: HierarchicalState) -> HierarchicalState: """Coordinate between teams.""" prompt = f"Which team should handle: {state['task']}? research or engineering" response = model.invoke(prompt) return {"team": response.content.strip().lower()}
def route_team(state: HierarchicalState) -> str: return state["team"]
main = StateGraph(HierarchicalState) main.add_node("coordinator", coordinator) main.add_node("research", research_team.compile()) main.add_node("engineering", eng_team.compile())
main.set_entry_point("coordinator") main.add_conditional_edges( "coordinator", route_team, {"research": "research", "engineering": "engineering"} )
organization = main.compile()

from typing import TypedDict, Literal
from langgraph.graph import StateGraph, END
from langchain_anthropic import ChatAnthropic
from pydantic import BaseModel

class Route(BaseModel):
    agent: Literal["researcher", "coder", "writer"]
    reason: str

class TeamState(TypedDict):
    task: str
    route: dict
    result: str

model = ChatAnthropic(model="claude-opus-4-5")
router_model = model.with_structured_output(Route)

def supervisor(state: TeamState) -> TeamState:
    route = router_model.invoke(
        f"Route this task: {state['task']}\n"
        "Options: researcher (facts), coder (code), writer (content)"
    )
    return {"route": route.model_dump()}

def researcher(state: TeamState) -> TeamState:
    resp = model.invoke(f"Research: {state['task']}")
    return {"result": resp.content}

def coder(state: TeamState) -> TeamState:
    resp = model.invoke(f"Write code for: {state['task']}")
    return {"result": resp.content}

def writer(state: TeamState) -> TeamState:
    resp = model.invoke(f"Write content for: {state['task']}")
    return {"result": resp.content}

graph = StateGraph(TeamState)
graph.add_node("supervisor", supervisor)
for name, fn in [("researcher", researcher), ("coder", coder), ("writer", writer)]:
    graph.add_node(name, fn)
    graph.add_edge(name, END)

graph.set_entry_point("supervisor")
graph.add_conditional_edges(
    "supervisor",
    lambda s: s["route"]["agent"],
    {"researcher": "researcher", "coder": "coder", "writer": "writer"}
)

team = graph.compile()

